;const ST_CHATU8_COMFYUI_BASIC_AUTH_PATCH_FLAG='__stChatu8ComfyuiBasicAuthFetchPatched';
const ST_CHATU8_COMFYUI_BASIC_AUTH_OBSERVER_FLAG='__stChatu8ComfyuiBasicAuthObserver';

function getComfyuiBasicAuthSettings(){
    const settings=extension_settings[extensionName]||(extension_settings[extensionName]={});
    return{
        baseUrl:typeof settings.comfyuiUrl==='string'?settings.comfyuiUrl.trim():'',
        username:typeof settings.comfyuiBasicAuthUsername==='string'?settings.comfyuiBasicAuthUsername.trim():'',
        password:typeof settings.comfyuiBasicAuthPassword==='string'?settings.comfyuiBasicAuthPassword:'',
    };
}

function encodeBasicAuthValue(value){
    try{
        const bytes=new TextEncoder().encode(value);
        let binary='';
        for(const byte of bytes){
            binary+=String.fromCharCode(byte);
        }
        return btoa(binary);
    }catch{
        return btoa(value);
    }
}

function parseUrlSafe(value){
    try{
        return new URL(value,window.location.href);
    }catch{
        return null;
    }
}

function matchesComfyuiUrl(requestUrl,comfyuiBaseUrl){
    const request=parseUrlSafe(requestUrl);
    const base=parseUrlSafe(comfyuiBaseUrl);
    if(!request||!base){
        return false;
    }

    if(request.origin!==base.origin){
        return false;
    }

    const basePath=base.pathname.replace(/\/+$/,'');
    const requestPath=request.pathname.replace(/\/+$/,'');
    if(!basePath||basePath==='/'){
        return true;
    }

    return requestPath===basePath||requestPath.startsWith(basePath+'/');
}

function installComfyuiBasicAuthFetchPatch(){
    if(window[ST_CHATU8_COMFYUI_BASIC_AUTH_PATCH_FLAG]){
        return;
    }

    const nativeFetch=window.fetch.bind(window);
    window.fetch=function patchedComfyuiFetch(input,init){
        try{
            const{baseUrl,username,password}=getComfyuiBasicAuthSettings();
            const requestUrl=input instanceof Request?input.url:String(input||'');

            if(baseUrl&&username&&matchesComfyuiUrl(requestUrl,baseUrl)){
                const headers=new Headers(input instanceof Request?input.headers:undefined);
                if(init?.headers){
                    const extraHeaders=new Headers(init.headers);
                    extraHeaders.forEach((value,key)=>headers.set(key,value));
                }

                headers.delete('X-CSRF-Token');
                headers.set('Authorization',`Basic ${encodeBasicAuthValue(`${username}:${password}`)}`);

                if(input instanceof Request){
                    return nativeFetch(new Request(input,{...init,headers}));
                }

                return nativeFetch(input,{...init,headers});
            }
        }catch(error){
            console.warn('st-chatu8: failed to inject ComfyUI basic auth header',error);
        }

        return nativeFetch(input,init);
    };

    window[ST_CHATU8_COMFYUI_BASIC_AUTH_PATCH_FLAG]=true;
}

function bindComfyuiBasicAuthFields(root=document){
    const usernameInput=root.querySelector('#comfyuiBasicAuthUsername');
    const passwordInput=root.querySelector('#comfyuiBasicAuthPassword');
    if(!usernameInput||!passwordInput){
        return;
    }

    const settings=extension_settings[extensionName]||(extension_settings[extensionName]={});
    if(usernameInput.dataset.stChatu8Bound!=='true'){
        usernameInput.addEventListener('input',()=>{
            const currentSettings=extension_settings[extensionName]||(extension_settings[extensionName]={});
            currentSettings.comfyuiBasicAuthUsername=usernameInput.value||'';
            saveSettingsDebounced();
        });
        usernameInput.dataset.stChatu8Bound='true';
    }
    if(passwordInput.dataset.stChatu8Bound!=='true'){
        passwordInput.addEventListener('input',()=>{
            const currentSettings=extension_settings[extensionName]||(extension_settings[extensionName]={});
            currentSettings.comfyuiBasicAuthPassword=passwordInput.value||'';
            saveSettingsDebounced();
        });
        passwordInput.dataset.stChatu8Bound='true';
    }

    const nextUsername=typeof settings.comfyuiBasicAuthUsername==='string'?settings.comfyuiBasicAuthUsername:'';
    const nextPassword=typeof settings.comfyuiBasicAuthPassword==='string'?settings.comfyuiBasicAuthPassword:'';
    if(usernameInput.value!==nextUsername){
        usernameInput.value=nextUsername;
    }
    if(passwordInput.value!==nextPassword){
        passwordInput.value=nextPassword;
    }
}

function bootComfyuiBasicAuthSupport(){
    installComfyuiBasicAuthFetchPatch();
    bindComfyuiBasicAuthFields(document);

    if(window[ST_CHATU8_COMFYUI_BASIC_AUTH_OBSERVER_FLAG]||!document.body){
        return;
    }

    const observer=new MutationObserver(()=>bindComfyuiBasicAuthFields(document));
    observer.observe(document.body,{childList:true,subtree:true});
    window[ST_CHATU8_COMFYUI_BASIC_AUTH_OBSERVER_FLAG]=observer;
}

if(document.readyState==='loading'){
    document.addEventListener('DOMContentLoaded',bootComfyuiBasicAuthSupport,{once:true});
}else{
    bootComfyuiBasicAuthSupport();
}
